// TestEvaluationNamespaceScoping tests that evaluations are scoped to namespaces
func TestEvaluationNamespaceScoping(t *testing.T) {
	store := &mockStorage{
		getFlagFunc: func(ctx context.Context, req storage.ResourceRequest) (*flipt.Flag, error) {
			ns := req.GetNamespace()
			key := req.GetKey()

			// Only return flag if it's in the expected namespace
			if ns == "production" && key == "prod-flag" {
				return &flipt.Flag{
					NamespaceKey: "production",
					Key:          "prod-flag",
					Enabled:      true,
					Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
				}, nil
			}

			return nil, errs.ErrNotFound("flag not found in namespace")
		},
		getEvaluationRolloutsFunc: func(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRollout, error) {
			return []*storage.EvaluationRollout{}, nil
		},
	}

	mux := setupEvaluationServer(t, store)
	server := httptest.NewServer(mux)
	defer server.Close()

	// Test production namespace
	reqBody := map[string]interface{}{
		"namespaceKey": "production",
		"flagKey":      "prod-flag",
		"entityId":     "user123",
	}

	body, err := json.Marshal(reqBody)
	require.NoError(t, err)

	resp, err := http.Post(server.URL+"/evaluate/v1/boolean", "application/json", bytes.NewReader(body))
	require.NoError(t, err)
	defer resp.Body.Close()

	assert.Equal(t, http.StatusOK, resp.StatusCode)

	var result map[string]interface{}
	err = json.NewDecoder(resp.Body).Decode(&result)
	require.NoError(t, err)

	assert.Equal(t, "prod-flag", result["flagKey"])
	assert.True(t, result["enabled"].(bool))
}

