// TestBooleanEvaluationWithSegmentMatch tests boolean evaluation with segment matching
func TestBooleanEvaluationWithSegmentMatch(t *testing.T) {
	store := &mockStorage{
		getFlagFunc: func(ctx context.Context, req storage.ResourceRequest) (*flipt.Flag, error) {
			return &flipt.Flag{
				NamespaceKey: "default",
				Key:          "feature-flag",
				Enabled:      false,
				Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
			}, nil
		},
		getEvaluationRolloutsFunc: func(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRollout, error) {
			return []*storage.EvaluationRollout{
				{
					NamespaceKey: "default",
					Rank:         1,
					RolloutType:  flipt.RolloutType_SEGMENT_ROLLOUT_TYPE,
					Segment: &storage.RolloutSegment{
						Value:           true,
						SegmentOperator: flipt.SegmentOperator_OR_SEGMENT_OPERATOR,
						Segments: map[string]*storage.EvaluationSegment{
							"premium-users": {
								SegmentKey: "premium-users",
								MatchType:  flipt.MatchType_ANY_MATCH_TYPE,
								Constraints: []storage.EvaluationConstraint{
									{
										Type:     flipt.ComparisonType_STRING_COMPARISON_TYPE,
										Property: "plan",
										Operator: flipt.OpEQ,
										Value:    "premium",
									},
								},
							},
						},
					},
				},
			}, nil
		},
	}

	mux := setupEvaluationServer(t, store)
	server := httptest.NewServer(mux)
	defer server.Close()

	reqBody := map[string]interface{}{
		"namespaceKey": "default",
		"flagKey":      "feature-flag",
		"entityId":     "user123",
		"context": map[string]string{
			"plan": "premium",
		},
	}

	body, err := json.Marshal(reqBody)
	require.NoError(t, err)

	resp, err := http.Post(server.URL+"/evaluate/v1/boolean", "application/json", bytes.NewReader(body))
	require.NoError(t, err)
	defer resp.Body.Close()

	assert.Equal(t, http.StatusOK, resp.StatusCode)

	var result map[string]interface{}
	err = json.NewDecoder(resp.Body).Decode(&result)
	require.NoError(t, err)

	assert.True(t, result["enabled"].(bool))
	assert.Equal(t, "MATCH_EVALUATION_REASON", result["reason"])
}

// TestVariantEvaluationSuccess tests successful variant flag evaluation
func TestVariantEvaluationSuccess(t *testing.T) {
	store := &mockStorage{
		getFlagFunc: func(ctx context.Context, req storage.ResourceRequest) (*flipt.Flag, error) {
			return &flipt.Flag{
				NamespaceKey: "default",
				Key:          "variant-flag",
				Enabled:      true,
				Type:         flipt.FlagType_VARIANT_FLAG_TYPE,
			}, nil
		},
		getEvaluationRulesFunc: func(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRule, error) {
			return []*storage.EvaluationRule{
				{
					ID:      "rule1",
					FlagKey: "variant-flag",
					Rank:    0,
					Segments: map[string]*storage.EvaluationSegment{
						"beta-users": {
							SegmentKey: "beta-users",
							MatchType:  flipt.MatchType_ALL_MATCH_TYPE,
							Constraints: []storage.EvaluationConstraint{
								{
									Type:     flipt.ComparisonType_STRING_COMPARISON_TYPE,
									Property: "role",
									Operator: flipt.OpEQ,
									Value:    "beta",
								},
							},
						},
					},
				},
			}, nil
		},
		getEvaluationDistributionsFunc: func(ctx context.Context, req storage.IDRequest) ([]*storage.EvaluationDistribution, error) {
			return []*storage.EvaluationDistribution{
				{
					ID:         "dist1",
					RuleID:     "rule1",
					VariantID:  "variant1",
					VariantKey: "control",
					Rollout:    100,
				},
			}, nil
		},
	}

	mux := setupEvaluationServer(t, store)
	server := httptest.NewServer(mux)
	defer server.Close()

	reqBody := map[string]interface{}{
		"namespaceKey": "default",
		"flagKey":      "variant-flag",
		"entityId":     "user123",
		"context": map[string]string{
			"role": "beta",
		},
	}

	body, err := json.Marshal(reqBody)
	require.NoError(t, err)

	resp, err := http.Post(server.URL+"/evaluate/v1/variant", "application/json", bytes.NewReader(body))
	require.NoError(t, err)
	defer resp.Body.Close()

	assert.Equal(t, http.StatusOK, resp.StatusCode)

	var result map[string]interface{}
	err = json.NewDecoder(resp.Body).Decode(&result)
	require.NoError(t, err)

	assert.True(t, result["match"].(bool))
	assert.Equal(t, "control", result["variantKey"])
	assert.Equal(t, "MATCH_EVALUATION_REASON", result["reason"])
	assert.Equal(t, "variant-flag", result["flagKey"])
	if segmentKeys, ok := result["segmentKeys"].([]interface{}); ok {
		assert.Len(t, segmentKeys, 1)
	}
}

